return $input.all().map((item, i) => {
  const subject = item.json.subject || '';
  const from = item.json.from || '';
  const text = (item.json.text || item.json.snippet || '').slice(0, 6000);
  const system = "You classify job-application emails and output JSON only. Set is_application_confirmation=true ONLY when the email confirms the user has ALREADY SUBMITTED an application to a specific hiring company for a specific role (e.g. 'we received your application', 'thanks for applying to <company>'). Set is_application_confirmation=false for everything else, including: reminders to COMPLETE, FINISH, CONTINUE, or SUBMIT an application ('almost there', 'complete your application', 'finish applying') which mean it was NOT submitted; interview invites; rejections; job alerts or recommendations; newsletters; marketing. The company must be the actual HIRING company - job boards and ATS platforms (Indeed, LinkedIn, Glassdoor, Greenhouse, Lever, Workday, Ashby) are NOT the hiring company, so if only a platform is named with no real employer, set false and leave company empty. The job title usually follows a phrase like 'your application for', 'the position of', or 'the role of'; it may be preceded by a requisition/job ID (e.g. R0954602) and followed by a status like (Open) - extract only the readable job title and drop the ID and the status. Example: from 'received your application for: R0954602 IT Operations Analyst (OhioRISE) (Open)', the role is 'IT Operations Analyst (OhioRISE)'. Extract 'company' (hiring company) and 'role' (job title); if it is not a confirmation or a field is unknown, use an empty string.";
  return {
    json: {
      gmailId: item.json.id,
      ollamaBody: {
        model: 'llama3.2:3b',
        stream: false,
        options: { temperature: 0 },
        format: {
          type: 'object',
          properties: {
            is_application_confirmation: { type: 'boolean' },
            company: { type: 'string' },
            role: { type: 'string' }
          },
          required: ['is_application_confirmation', 'company', 'role']
        },
        messages: [
          { role: 'system', content: system },
          { role: 'user', content: `Subject: ${subject}\n\nFrom: ${from}\n\nBody:\n${text}` }
        ]
      }
    },
    pairedItem: { item: i }
  };
});

const prompts = $('Build prompt').all();
return $input.all().map((item, i) => {
  const parsed = JSON.parse(item.json.message.content);
  return {
    json: { ...parsed, gmailId: prompts[i].json.gmailId },
    pairedItem: { item: i }
  };
});
